from .base import Adapter


class CsvAdapter(Adapter):
    """Adapter that parses CSV source data into records."""

    name = "csv"

    def __init__(self):
        self.source_type = "text/csv"
        self.delimiter = ","

    def adapt(self, source):
        lines = source.strip().split("\n")
        if len(lines) < 2:
            return {"error": "need header and at least one row"}
        headers = lines[0].split(self.delimiter)
        rows = []
        for line in lines[1:]:
            values = line.split(self.delimiter)
            rows.append(dict(zip(headers, values)))
        return {"headers": headers, "rows": rows}

