from .base import Adapter


class AdapterRegistry:
    """Registry that maps format names to adapter instances."""

    def __init__(self):
        self._adapters = {}

    def register(self, source_type, adapter):
        """Register an adapter for a specific source type."""
        if not isinstance(adapter, Adapter):
            raise TypeError("adapter must be an Adapter subclass")
        self._adapters[source_type] = adapter

    def lookup(self, source_type):
        """Look up the adapter registered for source_type."""
        return self._adapters.get(source_type)

    def list_types(self):
        return list(self._adapters.keys())

