class AdapterChain:
    """Chains multiple adapters into a sequential processing pipeline.

    Accepts any object with an adapt() method (duck typing).
    """

    def __init__(self):
        self._stages = []

    def add(self, stage):
        """Add an adapter stage to the chain."""
        self._stages.append(stage)
        return self

    def run(self, data):
        """Run the data through all chain stages."""
        result = data
        for stage in self._stages:
            result = stage.adapt(result)
            if result is None or (isinstance(result, dict) and "error" in result):
                break
        return result

    def stage_count(self):
        return len(self._stages)

