import pytest
from adapters.base import Converter
from adapters.json_adapter import JsonAdapter
from adapters.csv_adapter import CsvAdapter
from adapters.xml_adapter import XmlAdapter
from adapters.registry import AdapterRegistry
from adapters.chain import AdapterChain


class TestConverter:
    def test_not_implemented(self):
        c = Converter()
        with pytest.raises(NotImplementedError):
            c.convert({"x": 1})

    def test_describe(self):
        c = Converter()
        assert "Converter" in c.describe()
        assert "base" in c.describe()


class TestJsonAdapter:
    def test_parse_json(self):
        a = JsonAdapter()
        result = a.convert('{"key": "value"}')
        assert result == {"key": "value"}
        assert a.source_format == "application/json"

    def test_non_object(self):
        a = JsonAdapter()
        result = a.convert('[1, 2, 3]')
        assert result["error"] == "expected object"


class TestCsvAdapter:
    def test_parse_csv(self):
        a = CsvAdapter()
        result = a.convert("name,age\nAlice,30\nBob,25")
        assert len(result["rows"]) == 2
        assert result["rows"][0]["name"] == "Alice"
        assert a.source_type == "text/csv"

    def test_too_few_lines(self):
        a = CsvAdapter()
        result = a.convert("header_only")
        assert "error" in result


class TestXmlAdapter:
    def test_parse_xml(self):
        a = XmlAdapter()
        result = a.convert("<name>Alice</name><age>30</age>")
        assert result == {"name": "Alice", "age": "30"}
        assert a.source_name == "xml_input"

    def test_empty_xml(self):
        a = XmlAdapter()
        result = a.convert("   ")
        assert result == {}

    def test_encoding_attr(self):
        assert XmlAdapter.SOURCE_ENCODING == "utf-8"


class TestRegistry:
    def test_register_and_lookup(self):
        reg = AdapterRegistry()
        adapter = JsonAdapter()
        reg.register("json", adapter)
        found = reg.lookup("json")
        assert found is adapter

    def test_unknown_type(self):
        reg = AdapterRegistry()
        result = reg.lookup("unknown")
        assert result is None

    def test_type_check(self):
        reg = AdapterRegistry()
        with pytest.raises(TypeError):
            reg.register("bad", "not an adapter")

    def test_list_types(self):
        reg = AdapterRegistry()
        reg.register("csv", CsvAdapter())
        reg.register("xml", XmlAdapter())
        assert set(reg.list_types()) == {"csv", "xml"}


class TestChain:
    def test_single_stage(self):
        chain = AdapterChain()
        chain.add(JsonAdapter())
        result = chain.run('{"x": 1}')
        assert result == {"x": 1}

    def test_stops_on_error(self):
        chain = AdapterChain()
        chain.add(JsonAdapter())
        result = chain.run('[1, 2]')
        assert "error" in result
